import boto3
import sys

def create_sns_subscription(topic_arn, endpoint, protocol='https'):
    sns_client = boto3.client('sns')
    
    response = sns_client.subscribe(
        TopicArn=topic_arn,
        Protocol=protocol,
        Endpoint=endpoint
    )
    
    return response

def main():
    print("SNS Subscription Manager")
    print("-" * 50)
    
    topic_arn = input("Enter SNS Topic ARN: ").strip()
    
    if not topic_arn:
        print("Topic ARN is required")
        sys.exit(1)
    
    while True:
        print("\nSelect Protocol:")
        print("1. HTTPS")
        print("2. HTTP")
        print("3. Email")
        print("4. Email-JSON")
        print("5. SMS")
        print("6. SQS")
        print("7. Lambda")
        print("8. Exit")
        
        choice = input("Enter choice (1-8): ").strip()
        
        if choice == '8':
            print("Exiting...")
            break
        
        protocol_map = {
            '1': 'https',
            '2': 'http',
            '3': 'email',
            '4': 'email-json',
            '5': 'sms',
            '6': 'sqs',
            '7': 'lambda'
        }
        
        protocol = protocol_map.get(choice)
        
        if not protocol:
            print("Invalid choice")
            continue
        
        endpoint = input(f"Enter {protocol.upper()} endpoint: ").strip()
        
        if not endpoint:
            print("Endpoint cannot be empty")
            continue
        
        try:
            response = create_sns_subscription(topic_arn, endpoint, protocol)
            subscription_arn = response.get('SubscriptionArn', 'pending confirmation')
            print(f"\nSubscription created successfully!")
            print(f"Subscription ARN: {subscription_arn}")
            print(f"Protocol: {protocol}")
            print(f"Endpoint: {endpoint}")
        except Exception as e:
            print(f"Error creating subscription: {str(e)}")
        
        another = input("\nCreate another subscription? (y/n): ").strip().lower()
        if another != 'y':
            break

if __name__ == "__main__":
    main()